3	import { buildPngResponse, handleGET } from '@/lib/api';
4	import azureCache from '@/lib/azure';
5	import { CONTAINER_MUGSHOTS } from '@/lib/azureConfig';
6	import { InternalError, normalizeUnknownError } from '@/lib/errors';
7	import { streamToBuffer } from '@/lib/stream';
8	import playerService from '@/services/Player';
9	
10	/**
11	 * Retrieves the mugshot image of a player based on their ID.
12	 *
13	 * @param {Object} params - The parameters object.
14	 * @param {Record<string, string>} params.params - A record containing the player's ID.
15	 * @returns {Promise<Buffer | null>} A promise that resolves to a Buffer containing the player's mugshot image,
16	 * or `null` if the player is not found.
17	 *
18	 * @throws {Error} Throws an error if the image body download fails.
19	 */
20	async function getPlayerMugshot(
21	    { params }: { params: Record<string, string> },
22	): Promise<Buffer | null> {
23	    try {
24	        const playerId = Number(params.id);
25	        if (Number.isNaN(playerId)) return null;
26	
27	        const player = await playerService.getById(playerId);
28	        if (!player) return null;
29	        const containerClient = azureCache.getContainerClient(CONTAINER_MUGSHOTS);
30	        const playerLogin = await playerService.getLogin(params.id);
31	        let blobClient = containerClient.getBlobClient(playerLogin ? `${playerLogin}.jpg` : 'manofmystery.jpg');
32	
33	        if (player.anonymous ||
34	            (playerLogin && !(await blobClient.exists()))) {
35	            blobClient = containerClient.getBlobClient('manofmystery.jpg');
36	        }
37	
38	        const downloadBlockBlobResponse = await blobClient.download(0);
39	        if (!downloadBlockBlobResponse.readableStreamBody) {
40	            throw new InternalError('Image body download failed.', {
41	                details: {
42	                    resource: 'player-mugshot',
43	                    playerId,
44	                },
45	            });
46	        }
47	        return await streamToBuffer(downloadBlockBlobResponse.readableStreamBody);
48	    }
49	    catch (error) {
50	        throw normalizeUnknownError(error, {
51	            details: {
52	                resource: 'player-mugshot',
53	                playerId: params.id,
54	            },
55	        });
56	    }
57	}
58	
59	/**
60	 * Handles the GET request for retrieving a player's mugshot.
61	 *
62	 * @param request - The incoming Next.js request object.
63	 * @param props - An object containing route parameters.
64	 * @param props.params - A promise resolving to a record of route parameters, including `id`.
65	 * @returns A response containing the player's mugshot in PNG format.
66	 */
67	export const GET = async (request: NextRequest, props: { params: Promise<Record<string, string>> }) => {
68	    const params = await props.params;
69	    return handleGET(
70	        () => getPlayerMugshot({ params }),
71	        { params },
72	        { buildResponse: buildPngResponse },
73	    );
74	};
