const [mugshotReady, setMugshotReady] = useState(false);
// Fading via opacity alone would still leave these hit-testable and
// exposed to assistive tech while "hidden" — also disable pointer events
// and pull them out of the accessibility tree until they're shown.
const overlayStyle = {
    opacity: mugshotReady ? 1 : 0,
    pointerEvents: mugshotReady ? 'auto' : 'none',
    transition: 'opacity 150ms ease',
} as const;

return (
    <Box w="100%" pos="relative" className={classes.imageContainer}>
        <PlayerMugshot player={player} onReady={() => setMugshotReady(true)} />
        <Box
            className={classes.trophies}
            left="0.5em"
            top="0.5em"
            style={overlayStyle}
            aria-hidden={!mugshotReady}
        >
            <PlayerTrophies trophies={trophies} />
        </Box>
        <Box
            className={classes.badges}
            right="0.5em"
            bottom="0.5em"
            style={overlayStyle}
