23	    const [loaded, setLoaded] = useState(false);
24	
25	    const onReadyRef = useRef(onReady);
26	    useEffect(() => {
27	        onReadyRef.current = onReady;
28	    });
29	
30	    const handleReady = useCallback(() => {
31	        setLoaded(true);
